/**
 * Color Sort Puzzle (water-sort style) — pour colored segments between
 * tubes until each color is consolidated. Puzzles are generated by
 * dealing a shuffled multiset of color units directly into the colored
 * tubes (leaving the working tubes empty), which is the standard
 * water-sort generation approach.
 *
 * An earlier version tried to "shuffle" by reverse-simulating legal pours
 * from the solved state — but pouring a solved (monochrome) tube always
 * moves its *entire* contents at once, so every reverse move just swapped
 * which tube held a color without ever mixing them. The puzzle was left
 * permanently solved, which sent the post-shuffle "already solved?" retry
 * into infinite recursion. Original code.
 */
import { $, sfx, isMuted, toggleMute, bestScore } from '../shared/engine.js';

const GAME_ID = 'color-sort';
const CAPACITY = 4;
const PALETTE = ['#ff5c8a', '#22d3ee', '#ffb444', '#7c5cff', '#35e0a1', '#ff8a5c', '#c084fc', '#5cffb8'];
const DIFFICULTIES = { easy: 4, medium: 6, hard: 8 };

let difficulty = 'medium';
let tubes, selected, moves, history;

function reset() {
  const numColors = DIFFICULTIES[difficulty];
  tubes = shuffledDeal(numColors);
  tubes.push([], []); // two working tubes

  selected = null;
  moves = 0;
  history = [];
  $('#moves').textContent = '0';
  $('#overlay').hidden = true;
  render();
}

function shuffledDeal(numColors) {
  let dealt;
  let attempts = 0;
  do {
    const units = [];
    for (let c = 0; c < numColors; c++) for (let i = 0; i < CAPACITY; i++) units.push(c);
    for (let i = units.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [units[i], units[j]] = [units[j], units[i]];
    }
    dealt = Array.from({ length: numColors }, () => units.splice(0, CAPACITY));
    attempts++;
    // A freshly dealt board reading as "solved" would need every tube to
    // luckily land monochrome — astronomically unlikely, but re-roll just in case.
  } while (attempts < 10 && dealt.every((t) => t.every((c) => c === t[0])));
  return dealt;
}

function canPour(a, b) {
  const from = tubes[a], to = tubes[b];
  if (!from.length) return false;
  if (to.length >= CAPACITY) return false;
  const topColor = from[from.length - 1];
  if (to.length && to[to.length - 1] !== topColor) return false;
  return true;
}

function pour(a, b, silent = false) {
  const from = tubes[a], to = tubes[b];
  const topColor = from[from.length - 1];
  let count = 0;
  for (let i = from.length - 1; i >= 0 && from[i] === topColor; i--) count++;
  const space = CAPACITY - to.length;
  const amount = Math.min(count, space);
  for (let i = 0; i < amount; i++) to.push(from.pop());
  if (!silent) sfx.pop();
  return amount;
}

function isSolved() {
  const nonEmpty = tubes.filter((t) => t.length > 0);
  return nonEmpty.every((t) => t.length === CAPACITY && t.every((c) => c === t[0]));
}

function render() {
  const el = $('#tubes');
  el.innerHTML = tubes
    .map((tube, i) => {
      const segments = tube.map((color) => `<div class="segment" style="background:${PALETTE[color]}"></div>`).join('');
      return `<div class="tube${selected === i ? ' selected' : ''}" data-i="${i}">${segments}</div>`;
    })
    .join('');
  el.querySelectorAll('.tube').forEach((tubeEl) => {
    tubeEl.addEventListener('click', () => handleTube(Number(tubeEl.dataset.i)));
  });
}

function handleTube(i) {
  if (selected === null) {
    if (!tubes[i].length) return;
    selected = i;
    sfx.click();
    render();
    return;
  }

  if (selected === i) {
    selected = null;
    render();
    return;
  }

  if (canPour(selected, i)) {
    history.push(tubes.map((t) => [...t]));
    pour(selected, i);
    moves++;
    $('#moves').textContent = moves;
    selected = null;
    render();
    if (isSolved()) win();
  } else {
    sfx.invalid();
    selected = i;
    render();
  }
}

function undo() {
  if (!history.length) return;
  tubes = history.pop();
  selected = null;
  render();
}

function win() {
  sfx.win();
  const { isNewBest, best } = bestScore(`${GAME_ID}-${difficulty}`, Math.max(0, 1000 - moves));
  const overlay = $('#overlay');
  overlay.hidden = false;
  overlay.innerHTML = `
    <h1>Sorted!</h1>
    <div class="overlay__score">${moves} moves</div>
    <p>${isNewBest ? 'New best score!' : `Best score: ${best}`}</p>
    <button class="g-btn" id="start-btn">Play Again</button>
  `;
  $('#start-btn').addEventListener('click', reset);
}

$('#diff-row').addEventListener('click', (e) => {
  const btn = e.target.closest('.option-btn');
  if (!btn) return;
  $('#diff-row').querySelectorAll('.option-btn').forEach((b) => b.classList.remove('is-active'));
  btn.classList.add('is-active');
  difficulty = btn.dataset.diff;
  reset();
});

$('#mute-btn').addEventListener('click', () => {
  const muted = toggleMute();
  $('#mute-btn').textContent = muted ? '🔇' : '🔊';
});
$('#mute-btn').textContent = isMuted() ? '🔇' : '🔊';

$('#undo-btn').addEventListener('click', undo);
$('#restart-btn').addEventListener('click', reset);
$('#start-btn').addEventListener('click', reset);

tubes = [];
render();
